import os
import json
import pymysql
from google.cloud import secretmanager


def get_db_password():
    """Retrieve database password from Secret Manager."""
    client = secretmanager.SecretManagerServiceClient()
    secret_name = os.environ.get("DB_PASSWORD_SECRET")
    if secret_name:
        response = client.access_secret_version(request={"name": secret_name})
        return response.payload.data.decode("UTF-8")
    return os.environ.get("DB_PASSWORD", "")


def get_connection():
    """Create a database connection to Cloud SQL MySQL."""
    connection = pymysql.connect(
        unix_socket=f"/cloudsql/{os.environ['CLOUD_SQL_CONNECTION_NAME']}",
        user=os.environ["DB_USER"],
        password=get_db_password(),
        database=os.environ["DB_NAME"],
        charset="utf8mb4",
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=10,
        read_timeout=30,
    )
    return connection


# Define allowed tables, columns, and operators to prevent injection
ALLOWED_TABLES = {"products", "users", "orders", "categories"}

ALLOWED_COLUMNS = {
    "products": {"id", "name", "description", "price", "category_id", "status", "created_at", "updated_at"},
    "users": {"id", "username", "email", "status", "created_at"},
    "orders": {"id", "user_id", "status", "total", "created_at"},
    "categories": {"id", "name", "parent_id"},
}

ALLOWED_OPERATORS = {
    "eq": "=",
    "neq": "!=",
    "gt": ">",
    "gte": ">=",
    "lt": "<",
    "lte": "<=",
    "like": "LIKE",
    "in": "IN",
    "between": "BETWEEN",
    "is_null": "IS NULL",
    "is_not_null": "IS NOT NULL",
}

ALLOWED_SORT_DIRECTIONS = {"asc", "desc"}

MAX_LIMIT = 500
DEFAULT_LIMIT = 50


def validate_table(table_name):
    """Validate that the table name is in the allowed list."""
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Invalid table: '{table_name}'. Allowed tables: {', '.join(sorted(ALLOWED_TABLES))}")
    return table_name


def validate_column(table_name, column_name):
    """Validate that the column name is allowed for the given table."""
    allowed = ALLOWED_COLUMNS.get(table_name, set())
    if column_name not in allowed:
        raise ValueError(f"Invalid column: '{column_name}' for table '{table_name}'. Allowed: {', '.join(sorted(allowed))}")
    return column_name


def validate_operator(operator):
    """Validate that the operator is in the allowed list."""
    if operator not in ALLOWED_OPERATORS:
        raise ValueError(f"Invalid operator: '{operator}'. Allowed: {', '.join(sorted(ALLOWED_OPERATORS.keys()))}")
    return ALLOWED_OPERATORS[operator]


def build_dynamic_query(table, filters=None, sort_by=None, sort_dir=None,
                        limit=None, offset=None, select_columns=None):
    """
    Build a dynamic SQL query securely using parameterized queries.

    Parameters:
        table (str): Table name (must be in ALLOWED_TABLES)
        filters (list): List of dicts with 'column', 'operator', 'value' keys
        sort_by (str): Column to sort by
        sort_dir (str): Sort direction ('asc' or 'desc')
        limit (int): Maximum number of results
        offset (int): Number of results to skip
        select_columns (list): Specific columns to select

    Returns:
        tuple: (query_string, params_list)
    """
    # Validate table
    validated_table = validate_table(table)

    # Build SELECT clause with validated column names
    if select_columns:
        validated_select = []
        for col in select_columns:
            validated_select.append(f"`{validate_column(validated_table, col)}`")
        select_clause = ", ".join(validated_select)
    else:
        select_clause = "*"

    # Use backtick-quoted identifier (already validated against allowlist)
    query = f"SELECT {select_clause} FROM `{validated_table}`"
    params = []

    # Build WHERE clause
    if filters:
        where_conditions = []

        for f in filters:
            column = validate_column(validated_table, f["column"])
            operator_key = f.get("operator", "eq")
            sql_operator = validate_operator(operator_key)

            if operator_key == "is_null":
                where_conditions.append(f"`{column}` IS NULL")

            elif operator_key == "is_not_null":
                where_conditions.append(f"`{column}` IS NOT NULL")

            elif operator_key == "in":
                values = f.get("value", [])
                if not isinstance(values, list) or len(values) == 0:
                    raise ValueError(f"'in' operator requires a non-empty list for column '{column}'")
                if len(values) > 100:
                    raise ValueError(f"'in' operator limited to 100 values, got {len(values)}")
                placeholders = ", ".join(["%s"] * len(values))
                where_conditions.append(f"`{column}` IN ({placeholders})")
                params.extend(values)

            elif operator_key == "between":
                values = f.get("value", [])
                if not isinstance(values, list) or len(values) != 2:
                    raise ValueError(f"'between' operator requires exactly 2 values for column '{column}'")
                where_conditions.append(f"`{column}` BETWEEN %s AND %s")
                params.extend(values)

            elif operator_key == "like":
                value = f.get("value", "")
                # Escape special LIKE characters in the value itself
                escaped_value = value.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
                # Allow user to specify wildcard position via 'match' parameter
                match_type = f.get("match", "contains")
                if match_type == "starts_with":
                    like_value = f"{escaped_value}%"
                elif match_type == "ends_with":
                    like_value = f"%{escaped_value}"
                elif match_type == "exact":
                    like_value = escaped_value
                else:  # contains
                    like_value = f"%{escaped_value}%"
                where_conditions.append(f"`{column}` LIKE %s")
                params.append(like_value)

            else:
                value = f.get("value")
                if value is None:
                    raise ValueError(f"Missing 'value' for filter on column '{column}'")
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(value)

        if where_conditions:
            # Support AND/OR logic - default to AND
            logic = "AND"
            query += " WHERE " + f" {logic} ".join(where_conditions)

    # Build ORDER BY clause
    if sort_by:
        validated_sort_col = validate_column(validated_table, sort_by)
        direction = "ASC"
        if sort_dir and sort_dir.lower() in ALLOWED_SORT_DIRECTIONS:
            direction = sort_dir.upper()
        query += f" ORDER BY `{validated_sort_col}` {direction}"

    # Build LIMIT/OFFSET clause using parameterized values
    if limit is not None:
        limit = min(int(limit), MAX_LIMIT)
    else:
        limit = DEFAULT_LIMIT
    query += " LIMIT %s"
    params.append(limit)

    if offset is not None:
        offset = max(int(offset), 0)
        query += " OFFSET %s"
        params.append(offset)

    return query, params


def build_count_query(table, filters=None):
    """Build a COUNT query for pagination metadata."""
    query, params = build_dynamic_query(
        table=table,
        filters=filters,
        select_columns=None,
        sort_by=None,
        limit=None,
        offset=None,
    )
    # Replace the SELECT and LIMIT parts for counting
    # Rebuild cleanly for count
    validated_table = validate_table(table)
    count_query = f"SELECT COUNT(*) as total FROM `{validated_table}`"

    # Reuse filter logic
    count_params = []
    if filters:
        # Re-extract WHERE clause from the built query
        where_idx = query.find(" WHERE ")
        limit_idx = query.find(" LIMIT ")
        order_idx = query.find(" ORDER BY ")

        end_idx = len(query)
        if order_idx != -1:
            end_idx = min(end_idx, order_idx)
        if limit_idx != -1:
            end_idx = min(end_idx, limit_idx)

        if where_idx != -1:
            where_clause = query[where_idx:end_idx]
            count_query += where_clause
            # Params for count exclude LIMIT/OFFSET params
            limit_params = 1  # LIMIT
            if " OFFSET " in query:
                limit_params = 2
            count_params = params[:-limit_params] if params else []

    return count_query, count_params


def search_api(request):
    """
    Cloud Function entry point for the search API.

    Expected JSON body:
    {
        "table": "products",
        "filters": [
            {"column": "name", "operator": "like", "value": "widget", "match": "contains"},
            {"column": "price", "operator": "gte", "value": 10.00},
            {"column": "price", "operator": "lte", "value": 100.00},
            {"column": "status", "operator": "eq", "value": "active"},
            {"column": "category_id", "operator": "in", "value": [1, 2, 3]}
        ],
        "select": ["id", "name", "price", "status"],
        "sort_by": "price",
        "sort_dir": "asc",
        "limit": 20,
        "offset": 0,
        "include_count": true
    }
    """
    # Handle CORS preflight
    if request.method == "OPTIONS":
        headers = {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "POST, GET",
            "Access-Control-Allow-Headers": "Content-Type, Authorization",
            "Access-Control-Max-Age": "3600",
        }
        return ("", 204, headers)

    cors_headers = {"Access-Control-Allow-Origin": "*"}

    try:
        # Parse request
        if request.content_type and "application/json" in request.content_type:
            request_data = request.get_json(silent=True) or {}
        else:
            # Support query parameters for simple GET requests
            request_data = {}
            args = request.args
            if args.get("table"):
                request_data["table"] = args["table"]
            if args.get("limit"):
                request_data["limit"] = int(args["limit"])
            if args.get("offset"):
                request_data["offset"] = int(args["offset"])
            if args.get("sort_by"):
                request_data["sort_by"] = args["sort_by"]
            if args.get("sort_dir"):
                request_data["sort_dir"] = args["sort_dir"]

        # Validate required fields
        table = request_data.get("table")
        if not table:
            return (
                json.dumps({"error": "Missing required parameter: 'table'", "allowed_tables": sorted(ALLOWED_TABLES)}),
                400,
                {**cors_headers, "Content-Type": "application/json"},
            )

        filters = request_data.get("filters", [])
        select_columns = request_data.get("select")
        sort_by = request_data.get("sort_by")
        sort_dir = request_data.get("sort_dir")
        limit = request_data.get("limit", DEFAULT_LIMIT)
        offset = request_data.get("offset", 0)
        include_count = request_data.get("include_count", False)

        # Build the query securely
        query, params = build_dynamic_query(
            table=table,
            filters=filters,
            sort_by=sort_by,
            sort_dir=sort_dir,
            limit=limit,
            offset=offset,
            select_columns=select_columns,
        )

        # Execute the query
        connection = get_connection()
        try:
            with connection.cursor() as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()

                # Convert datetime objects for JSON serialization
                for row in results:
                    for key, value in row.items():
                        if hasattr(value, "isoformat"):
                            row[key] = value.isoformat()

                response_data = {
                    "success": True,
                    "data": results,
                    "count": len(results),
                    "limit": min(int(limit), MAX_LIMIT) if limit else DEFAULT_LIMIT,
                    "offset": int(offset) if offset else 0,
                }

                # Optionally include total count for pagination
                if include_count:
                    count_query, count_params = build_count_query(table, filters)
                    cursor.execute(count_query, count_params)
                    count_result = cursor.fetchone()
                    response_data["total"] = count_result["total"] if count_result else 0
                    total = response_data["total"]
                    current_limit = response_data["limit"]
                    current_offset = response_data["offset"]
                    response_data["has_more"] = (current_offset + current_limit) < total
                    response_data["total_pages"] = (total + current_limit - 1) // current_limit if current_limit > 0 else 0
                    response_data["current_page"] = (current_offset // current_limit) + 1 if current_limit > 0 else 1

        finally:
            connection.close()

        return (
            json.dumps(response_data, default=str),
            200,
            {**cors_headers, "Content-Type": "application/json"},
        )

    except ValueError as e:
        return (
            json.dumps({"success": False, "error": f"Validation error: {str(e)}"}),
            400,
            {**cors_headers, "Content-Type": "application/json"},
        )
